166: void ConnectionManagerImpl::initializeReadFilterCallbacks(Network::ReadFilterCallbacks& callbacks) {
167:   read_callbacks_ = &callbacks;
168:   dispatcher_ = &callbacks.connection().dispatcher();
169:   if (max_requests_during_dispatch_ != UINT32_MAX) {
170:     deferred_request_processing_callback_ =
171:         dispatcher_->createSchedulableCallback([this]() -> void { onDeferredRequestProcessing(); });
172:   }
173: 
174:   stats_.named_.downstream_cx_total_.inc();
175:   stats_.named_.downstream_cx_active_.inc();
176:   if (read_callbacks_->connection().ssl()) {
177:     stats_.named_.downstream_cx_ssl_total_.inc();
178:     stats_.named_.downstream_cx_ssl_active_.inc();
179:   }
180: 
181:   read_callbacks_->connection().addConnectionCallbacks(*this);
182: 
183:   if (config_->addProxyProtocolConnectionState() &&
184:       !read_callbacks_->connection()
185:            .streamInfo()
186:            .filterState()
187:            ->hasData<Network::ProxyProtocolFilterState>(Network::ProxyProtocolFilterState::key())) {
188:     read_callbacks_->connection().streamInfo().filterState()->setData(
189:         Network::ProxyProtocolFilterState::key(),
190:         std::make_unique<Network::ProxyProtocolFilterState>(Network::ProxyProtocolData{
191:             read_callbacks_->connection().connectionInfoProvider().remoteAddress(),
192:             read_callbacks_->connection().connectionInfoProvider().localAddress()}),
193:         StreamInfo::FilterState::StateType::ReadOnly,
194:         StreamInfo::FilterState::LifeSpan::Connection);
195:   }
196: 
197:   if (config_->idleTimeout()) {
198:     connection_idle_timer_ =
199:         dispatcher_->createScaledTimer(Event::ScaledTimerType::HttpDownstreamIdleConnectionTimeout,
200:                                        [this]() -> void { onIdleTimeout(); });
201:     connection_idle_timer_->enableTimer(config_->idleTimeout().value());
202:   }
203: 
204:   if (config_->maxConnectionDuration()) {
205:     connection_duration_timer_ =
206:         dispatcher_->createScaledTimer(Event::ScaledTimerType::HttpDownstreamMaxConnectionTimeout,
207:                                        [this]() -> void { onConnectionDurationTimeout(); });
208:     connection_duration_timer_->enableTimer(config_->maxConnectionDuration().value());
209:   }
210: 
211:   read_callbacks_->connection().setDelayedCloseTimeout(config_->delayedCloseTimeout());
212: 
213:   read_callbacks_->connection().setConnectionStats(
214:       {stats_.named_.downstream_cx_rx_bytes_total_, stats_.named_.downstream_cx_rx_bytes_buffered_,
215:        stats_.named_.downstream_cx_tx_bytes_total_, stats_.named_.downstream_cx_tx_bytes_buffered_,
216:        nullptr, &stats_.named_.downstream_cx_delayed_close_timeout_});
