321: void ConnectionManagerImpl::doDeferredStreamDestroy(ActiveStream& stream) {
322:   if (!stream.state_.is_internally_destroyed_) {
323:     ++closed_non_internally_destroyed_requests_;
324:     if (isPrematureRstStream(stream)) {
325:       ++number_premature_stream_resets_;
326:     }
327:   }
328:   if (stream.max_stream_duration_timer_ != nullptr) {
329:     stream.max_stream_duration_timer_->disableTimer();
330:     stream.max_stream_duration_timer_ = nullptr;
331:   }
332:   if (stream.stream_idle_timer_ != nullptr) {
333:     stream.stream_idle_timer_->disableTimer();
334:     stream.stream_idle_timer_ = nullptr;
335:   }
336:   stream.filter_manager_.disarmRequestTimeout();
337:   if (stream.request_header_timer_ != nullptr) {
338:     stream.request_header_timer_->disableTimer();
339:     stream.request_header_timer_ = nullptr;
340:   }
341:   if (stream.access_log_flush_timer_ != nullptr) {
342:     stream.access_log_flush_timer_->disableTimer();
343:     stream.access_log_flush_timer_ = nullptr;
344:   }
345: 
346:   // Only destroy the active stream if the underlying codec has notified us of
347:   // completion or we've internal redirect the stream.
348:   if (!stream.canDestroyStream()) {
349:     // Track that this stream is not expecting any additional calls apart from
350:     // codec notification.
351:     stream.state_.is_zombie_stream_ = true;
352:     return;
353:   }
354: 
355:   if (stream.response_encoder_ != nullptr) {
356:     stream.response_encoder_->getStream().registerCodecEventCallbacks(nullptr);
357:   }
358: 
359:   stream.completeRequest();
360:   stream.filter_manager_.onStreamComplete();
361: 
362:   // For HTTP/3, skip access logging here and add deferred logging info
363:   // to stream info for QuicStatsGatherer to use later.
364:   if (codec_ && codec_->protocol() == Protocol::Http3 &&
365:       // There was a downstream reset, log immediately.
366:       !stream.filter_manager_.sawDownstreamReset() &&
367:       // On recreate stream, log immediately.
368:       stream.response_encoder_ != nullptr &&
369:       Runtime::runtimeFeatureEnabled(
370:           "envoy.reloadable_features.quic_defer_logging_to_ack_listener")) {
371:     stream.deferHeadersAndTrailers();
372:   } else {
373:     // For HTTP/1 and HTTP/2, log here as usual.
374:     stream.log(AccessLog::AccessLogType::DownstreamEnd);
375:   }
376: 
377:   stream.filter_manager_.destroyFilters();
378: 
379:   dispatcher_->deferredDelete(stream.removeFromList(streams_));
380: 
381:   // The response_encoder should never be dangling (unless we're destroying a
382:   // stream we are recreating) as the codec level stream will either outlive the
383:   // ActiveStream, or be alive in deferred deletion queue at this point.
384:   if (stream.response_encoder_) {
385:     stream.response_encoder_->getStream().removeCallbacks(stream);
386:   }
387: 
388:   if (connection_idle_timer_ && streams_.empty()) {
389:     connection_idle_timer_->enableTimer(config_->idleTimeout().value());
390:   }
391:   maybeDrainDueToPrematureResets();
392: }
