2168:   // Only reap stream once.
2169:   if (state_.is_zombie_stream_) {
2170:     const bool skip_delay = shouldSkipDeferredCloseDelay();
2171:     connection_manager_.doDeferredStreamDestroy(*this);
2172:     // After destroying a zombie stream, check if the connection should be
2173:     // closed. doEndStream() call that created the zombie may have set
2174:     // drain_state_ to Closing, but checkForDeferredClose() couldn't close the
2175:     // connection at that time because streams_ wasn't empty yet.
2176:     if (connection_manager_.close_connection_on_zombie_stream_complete_) {
2177:       connection_manager_.checkForDeferredClose(skip_delay);
